use std::io::{self, BufRead};

fn factorial(x: i32) -> i32 {
    if x < 2 {
        return 1;
    } else {
        return x * factorial(x - 1);
    }
}

fn main() {
    let reader = io::stdin();
    let numbers: Vec<i32> =
        reader.lock()                           // (0)
            .lines().next().unwrap().unwrap() // (1)
            .split(' ').map(|s| s.trim())     // (2)
            .filter(|s| !s.is_empty())        // (3)
            .map(|s| s.parse().unwrap())      // (4)
            .collect();                       // (5)

    let mut min= numbers[0];
    if numbers[1] < min {
        min = numbers[1];
    }

    println!("{}", factorial(min));
}
